      return `mocked.jwt.token.${JSON.stringify(payload)}`;
    },
    verify: (token, secret) => {
      if (secret !== TEST_KEY) throw new Error('Invalid secret');
      const payloadStr = token.split('.')[2];
      return JSON.parse(Buffer.from(payloadStr, 'base64').toString());
    }
  }));

  describe('POST /login', () => {
    it('should return 200 with valid credentials', async () => {
      const response = await request(app)
        .post('/login')
        .send(TEST_USER);

      expect(response.status).toBe(200);
      expect(response.body).toHaveProperty('token');
      expect(typeof response.body.token).toBe('string');

      // Verify token payload
      const decoded = jwt.verify(response.body.token, TEST_KEY);
      expect(decoded.id).toBe(1);
      expect(decoded.role).toBe('user');
    });

    it('should return 401 with invalid credentials', async () => {
      const response = await request(app)
        .post('/login')
        .send({ email: 'wrong@example.com', password: 'wrongpass' });

      expect(response.status).toBe(401);
      expect(response.body).toEqual({ error: 'Invalid credentials' });
    });

    it('should reject expired tokens', async () => {
      // Create an expired token manually
