const amqp = require('amqplib');
const { createQueue } = require('./queue');

async function processOrder(message) {
  const order = JSON.parse(message.content.toString());
  let retries = 0;
  const maxRetries = 3;

  while (retries <= maxRetries) {
    try {
      // Simulate long-running processing
      await new Promise(resolve => setTimeout(resolve, 5000));
      console.log(`Processed order ${order.id}`);

      // Only acknowledge after successful processing
      message.ack();
      return;
    } catch (err) {
      retries++;
      console.error(`Attempt ${retries} failed for order ${order.id}:`, err);

      if (retries > maxRetries) {
        console.error(`Max retries exceeded for order ${order.id}, rejecting permanently`);
        message.nack(false, false); // Reject permanently
        return;
      }

      // Exponential backoff
      const delay = Math.pow(2, retries) * 1000;
      await new Promise(resolve => setTimeout(resolve, delay));
    }
  }
}

async function startConsumer() {
  const connection = await amqp.connect('amqp://localhost');
  const channel = await connection.createChannel();

  try {
    await channel.assertQueue('orders', { durable: true });
    await channel.prefetch(1); // Process one message at a time

    // Use manual acknowledgment
    channel.consume('orders', processOrder, { noAck: false });

    console.log('Order consumer started');
  } catch (error) {
    console.error('Error starting consumer:', error);
    await channel.close();
    await connection.close();
  }
}

startConsumer().catch(console.error);
```

The key fixes implemented:

1. **Proper Acknowledgment Timing**: Messages are only acknowledged after successful processing, preventing premature acks that could cause message loss.

2. **Retry Mechanism**: Added retry logic with exponential backoff (1s, 2s, 4s) up to 3 attempts for transient failures.

3. **Permanent Rejection**: After max retries, messages are rejected permanently (`message.nack(false, false)`) instead of being requeued indefinitely.

4. **Resource Management**: Added proper error handling and cleanup with try/catch blocks.

5. **Thread Safety**: Used `channel.prefetch(1)` to ensure only one unacknowledged message is processed at a time.

6. **Graceful Failure Handling**: The system now handles failures gracefully without dropping messages or leaking resources.

The race condition was caused by immediate acknowledgment before processing completion. This fix ensures messages are only acknowledged after successful processing, with proper retry handling for transient failures.

