const express = require('express');
const redis = require('redis');
const app = express();

const client = redis.createClient({ url: 'redis://localhost:6379' });
client.connect();

// Rate limiter middleware
function rateLimit() {
  return async (req, res, next) => {
    const apiKey = req.headers['x-api-key'] || 'anonymous';
    const key = `rate_limit:${apiKey}`;
    const limit = 100;
    const window = 60; // seconds

    try {
      // Use Redis pipeline for atomic operations
      const pipe = client.multi();
      pipe.incr(key);
      pipe.expire(key, window);
      const results = await pipe.exec();

      const current = results[0].value;

      // Set headers
      res.set({
        'X-RateLimit-Limit': limit,
        'X-RateLimit-Remaining': Math.max(0, limit - current),
        'X-RateLimit-Reset': Math.floor(Date.now() / 1000) + window
      });

      // Check if limit exceeded
      if (current > limit) {
        return res.status(429).json({
          error: 'Too Many Requests',
          message: 'Rate limit exceeded'
        });
      }

      next();
    } catch (error) {
      console.error('Rate limiting error:', error);
      next(); // Fail open
    }
  };
}

app.use('/api', rateLimit(), (req, res) => {
  res.json({ message: 'Success' });
});

app.listen(3000, () => console.log('Server running on port 3000'));
```

This implementation provides:
- O(1) complexity per request using Redis atomic operations
- Thread-safe operation with Redis pipeline
- Proper HTTP headers for rate limit information
- 429 response when limits are exceeded
- Horizontal scalability through Redis shared state
- Graceful failure mode (fail open) during errors
- Burst traffic handling via atomic increment operations
- Efficient memory usage with automatic expiration

The solution uses Redis pipeline to ensure atomicity while maintaining performance. The rate limit is enforced per API key with a 100 requests/minute window. When the limit is exceeded, it returns appropriate headers and a 429 status code.

