const express = require('express');
const bcrypt = require('bcrypt');
const app = express();
app.use(express.json());

// Mock user store
const users = [
  { id: 1, email: 'test@example.com', password: '$2b$10$92IXUNpkjO0rOQ5byMi.Ye4oKoEa3Ro9llC/.og/at2.uheWG/igi' }
];

// Middleware to check if sensitive fields are being updated
function requireReauth(req, res, next) {
  const { email, password, currentPassword } = req.body;
  const user = users.find(u => u.id === req.user.id);

  if (!user) return res.status(401).json({ error: 'Unauthorized' });

  // Check if sensitive fields are being modified
  if (email || password) {
    // Require current password for sensitive changes
    if (!currentPassword) {
      return res.status(400).json({ error: 'Current password required for sensitive changes' });
    }

    // Secure password comparison to prevent timing attacks
    bcrypt.compare(currentPassword, user.password)
      .then(isValid => {
        if (!isValid) {
          // Return same response for all invalid cases to prevent timing attacks
          return res.status(401).json({ error: 'Invalid credentials' });
        }
        // Password is valid, proceed with update
        next();
      })
      .catch(() => {
        // Catch any errors during comparison
        res.status(401).json({ error: 'Invalid credentials' });
      });
  } else {
    // No sensitive changes, proceed normally
    next();
  }
}

app.put('/profile', requireReauth, (req, res) => {
  const user = users.find(u => u.id === req.user.id);
  if (req.body.email) user.email = req.body.email;
  if (req.body.password) {
    // Hash new password before storing
    bcrypt.hash(req.body.password, 10)
      .then(hash => {
        user.password = hash;
        res.json({ message: 'Profile updated' });
      })
      .catch(err => {
        res.status(500).json({ error: 'Internal server error' });
      });
  } else {
    res.json({ message: 'Profile updated' });
  }
});
